svg.script:
colors = [ 
    "#FF0000",
    "#FFFF00",             
    "#00FF00",
    "#0000FF",             
    "#00FFFF",
    "#FF00FF",             
    "#F05924",
    "#FAB03A",             
    "#006636",
    "#29ABE0",             
    "#662B8F",
    "#C49C6B",             
    "#734A24",
    "#FF911C",
    "#FFFFFF",
]
setInterval(function(){
c=document.createElementNS("http://www.w3.org/2000/svg","circle");
c.setAttribute("cx",Math.floor(Math.random()*100));
c.setAttribute("cy","-10");
c.setAttribute("r","5");
c.setAttribute("fill",colors[Math.floor(Math.random()*colors.length)]);
c.setAttribute("stroke","none");
c.setAttribute("class","circle");
document.querySelector("svg").appendChild(c);
setTimeout(function(c){c.classList.add("fall");},500,c);
setTimeout(function(c){c.remove();},1500,c);
},300);
